def get_oidc_config():
    """Fetch and cache the OIDC provider's discovery document."""
    if not _oidc_config_cache:
        discovery_url = f"{OIDC_PROVIDER_URL.rstrip('/')}/.well-known/openid-configuration"
        response = requests.get(discovery_url, timeout=10)
        response.raise_for_status()
        _oidc_config_cache.update(response.json())
    return _oidc_config_cache


def get_jwks():
    """Fetch and cache the OIDC provider's JSON Web Key Set."""
    global _jwks_cache, _jwks_cache_time
    if not _jwks_cache or (time.time() - _jwks_cache_time > JWKS_CACHE_TTL):
        config = get_oidc_config()
        jwks_uri = config['jwks_uri']
        response = requests.get(jwks_uri, timeout=10)
        response.raise_for_status()
        _jwks_cache = response.json()
        _jwks_cache_time = time.time()
    return _jwks_cache


def generate_nonce():
    """Generate a cryptographically secure nonce for OIDC."""
    return secrets.token_urlsafe(32)


def generate_state():
    """Generate a cryptographically secure state parameter for CSRF protection."""
    return secrets.token_urlsafe(32)


def validate_id_token(id_token, expected_nonce):
    """
    Decode and validate the id_token using the provider's JWKS.

    Validates:
    - Signature using provider's public keys
    - Issuer (iss) matches the OIDC provider
    - Audience (aud) matches our client ID
    - Expiration (exp) is not passed
    - Nonce matches the one we sent in the authorization request
    """
    config = get_oidc_config()
    jwks = get_jwks()

    # Decode the token header to find the key ID
    unverified_header = jwt.get_unverified_header(id_token)
    kid = unverified_header.get('kid')

    # Find the matching key in the JWKS
    rsa_key = None
    for key in jwks.get('keys', []):
        if key.get('kid') == kid:
            rsa_key = key
            break

    if not rsa_key:
        raise JWTError("Unable to find matching key in JWKS for kid: {}".format(kid))

    # Decode and validate the token
    claims = jwt.decode(
        id_token,
        rsa_key,
        algorithms=['RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512'],
        audience=OIDC_CLIENT_ID,
        issuer=config['issuer'],
        options={
            'verify_exp': True,
            'verify_aud': True,
            'verify_iss': True,
            'verify_iat': True,
            'verify_nbf': False,  # nbf is optional in OIDC
        }
    )

    # Validate the nonce to prevent replay attacks
    # The nonce binds the id_token to the specific authentication request
    token_nonce = claims.get('nonce')
    if token_nonce is None:
        raise JWTError("id_token is missing required 'nonce' claim")
    if not secrets.compare_digest(str(token_nonce), str(expected_nonce)):
        raise JWTError("Nonce validation failed: id_token nonce does not match expected nonce")

    return claims


def login_required(f):
    """Decorator to require authentication for a route."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            session['next_url'] = request.url
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


