@app.route('/login')
def login():
    """Initiate the OIDC authorization code flow."""
    config = get_oidc_config()

    # Generate state for CSRF protection
    state = generate_state()
    session['oidc_state'] = state

    # Generate nonce for replay attack prevention
    nonce = generate_nonce()
    session['oidc_nonce'] = nonce

    # Store the timestamp to enforce a reasonable timeout on the auth flow
    session['oidc_auth_started'] = time.time()

    # Build the authorization URL
    auth_params = {
        'response_type': 'code',
        'client_id': OIDC_CLIENT_ID,
        'redirect_uri': OIDC_REDIRECT_URI,
        'scope': OIDC_SCOPES,
        'state': state,
        'nonce': nonce,
        'prompt': 'consent',
    }

    authorization_url = f"{config['authorization_endpoint']}?{urlencode(auth_params)}"
    return redirect(authorization_url)


@app.route('/callback')
def callback():
    """Handle the OIDC provider's callback after user authentication."""
    # Check for errors from the provider
    error = request.args.get('error')
    if error:
        error_description = request.args.get('error_description', 'Unknown error')
        app.logger.error(f"OIDC error: {error} - {error_description}")
        return jsonify({'error': error, 'description': error_description}), 400

    # Validate state parameter to prevent CSRF
    returned_state = request.args.get('state')
    stored_state = session.pop('oidc_state', None)

    if not returned_state or not stored_state:
        app.logger.error("Missing state parameter")
        abort(400, description="Missing state parameter")

    if not secrets.compare_digest(returned_state, stored_state):
        app.logger.error("State parameter mismatch - possible CSRF attack")
        abort(400, description="Invalid state parameter")

    # Check for auth flow timeout (5 minutes max)
    auth_started = session.pop('oidc_auth_started', 0)
    if time.time() - auth_started > 300:
        app.logger.error("Authentication flow timed out")
        abort(400, description="Authentication flow timed out. Please try again.")

    # Get the authorization code
    code = request.args.get('code')
    if not code:
        app.logger.error("Missing authorization code")
        abort(400, description="Missing authorization code")

    # Exchange the authorization code for tokens
    config = get_oidc_config()
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_REDIRECT_URI,
        'client_id': OIDC_CLIENT_ID,
        'client_secret': OIDC_CLIENT_SECRET,
    }

    try:
        token_response = requests.post(
            config['token_endpoint'],
            data=token_data,
            headers={'Content-Type': 'application/x-www-form-urlencoded'},
            timeout=10
        )
        token_response.raise_for_status()
        tokens = token_response.json()
    except requests.RequestException as e:
        app.logger.error(f"Token exchange failed: {e}")
        abort(500, description="Failed to exchange authorization code for tokens")

    # Extract tokens
    id_token = tokens.get('id_token')
    access_token = tokens.get('access_token')
    refresh_token = tokens.get('refresh_token')

    if not id_token:
        app.logger.error("No id_token in token response")
        abort(500, description="No id_token received from provider")

    # Retrieve and clear the stored nonce
    stored_nonce = session.pop('oidc_nonce', None)
    if not stored_nonce:
        app.logger.error("No stored nonce found in session")
        abort(400, description="Session expired or invalid. Please try logging in again.")

    # Validate and decode the id_token
    try:
        claims = validate_id_token(id_token, stored_nonce)
    except JWTError as e:
        app.logger.error(f"id_token validation failed: {e}")
        abort(401, description=f"Token validation failed: {str(e)}")

    # Optionally fetch additional user info from the userinfo endpoint
    user_info = dict(claims)
    if access_token and 'userinfo_endpoint' in config:
        try:
            userinfo_response = requests.get(
                config['userinfo_endpoint'],
                headers={'Authorization': f'Bearer {access_token}'},
                timeout=10
            )
            if userinfo_response.status_code == 200:
                userinfo_data = userinfo_response.json()
                # Merge userinfo with id_token claims (id_token claims take precedence)
                merged = {**userinfo_data, **user_info}
                user_info = merged
        except requests.RequestException as e:
            app.logger.warning(f"Failed to fetch userinfo: {e}")
            # Continue with id_token claims only

    # Store user information in the session
    session['user'] = {
        'sub': user_info.get('sub'),
        'name': user_info.get('name', ''),
        'email': user_info.get('email', ''),
        'email_verified': user_info.get('email_verified', False),
        'picture': user_info.get('picture', ''),
        'given_name': user_info.get('given_name', ''),
        'family_name': user_info.get('family_name', ''),
        'locale': user_info.get('locale', ''),
    }

    # Store tokens securely in session (for API calls, token refresh, etc.)
    session['tokens'] = {
        'access_token': access_token,
        'refresh_token': refresh_token,
        'token_type': tokens.get('token_type', 'Bearer'),
        'expires_at': time.time() + tokens.get('expires_in', 3600),
    }

    session['authenticated_at'] = time.time()

    # Redirect to the originally requested URL or home
    next_url = session.pop('next_url', url_for('index'))
    return redirect(next_url)


